import { Component, inject, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../application/services/auth.service';

interface NavItem {
  label: string;
  icon: string;
  route: string;
  roles?: string[];
}

@Component({
  selector: 'bo-backoffice-layout',
  templateUrl: './backoffice-layout.component.html',
  styleUrls: ['./backoffice-layout.component.css']
})
export class BackofficeLayoutComponent implements OnInit {
  private readonly authService = inject(AuthService);
  private readonly router = inject(Router);

  username = '';
  userRoles: string[] = [];
  sidebarOpen = true;

  navItems: NavItem[] = [
    { label: 'Panel Principal', icon: 'dashboard', route: '/dashboard' },
    { label: 'Expedientes', icon: 'folder', route: '/cases' },
    { label: 'Tareas Pendientes', icon: 'task', route: '/tasks' },
    { label: 'Usuarios', icon: 'people', route: '/admin/users', roles: ['ROLE_ADMIN'] },
    { label: 'Procedimientos', icon: 'settings', route: '/admin/procedures', roles: ['ROLE_ADMIN'] }
  ];

  ngOnInit(): void {
    const user = this.authService.currentUser;
    if (user) {
      this.username = user.username;
      this.userRoles = user.roles;
    }
  }

  logout(): void {
    this.authService.logout();
    this.router.navigate(['/login']);
  }

  toggleSidebar(): void {
    this.sidebarOpen = !this.sidebarOpen;
  }

  isVisible(item: NavItem): boolean {
    if (!item.roles || item.roles.length === 0) return true;
    return item.roles.some(role => this.userRoles.includes(role));
  }

  getIcon(icon: string): string {
    const icons: Record<string, string> = {
      dashboard: '📊',
      folder: '📁',
      task: '✅',
      people: '👥',
      settings: '⚙️'
    };
    return icons[icon] || '📄';
  }

  getPageTitle(): string {
    const currentRoute = this.router.url;
    const item = this.navItems.find(n => currentRoute.startsWith(n.route));
    return item?.label || 'Backoffice';
  }
}
<div class="flex h-screen bg-gray-50">
  <!-- Sidebar -->
  <aside
    class="bg-gray-900 text-white transition-all duration-300 flex flex-col"
    [class.w-64]="sidebarOpen"
    [class.w-20]="!sidebarOpen"
  >
    <div class="flex items-center justify-between p-4 border-b border-gray-700">
      <span *ngIf="sidebarOpen" class="text-lg font-semibold">Backoffice</span>
      <button
        (click)="toggleSidebar()"
        class="p-1 rounded hover:bg-gray-700 transition-colors"
        aria-label="Toggle sidebar"
      >
        {{ sidebarOpen ? '&#9664;' : '&#9654;' }}
      </button>
    </div>

    <nav class="flex-1 py-4">
      <a
        *ngFor="let item of navItems"
        [routerLink]="isVisible(item) ? [item.route] : null"
        [class.opacity-50]="!isVisible(item)"
        [class.pointer-events-none]="!isVisible(item)"
        routerLinkActive="bg-gray-700"
        class="flex items-center px-4 py-3 hover:bg-gray-700 transition-colors cursor-pointer"
      >
        <span class="text-xl w-8 text-center">{{ getIcon(item.icon) }}</span>
        <span *ngIf="sidebarOpen" class="ml-3">{{ item.label }}</span>
      </a>
    </nav>

    <div class="p-4 border-t border-gray-700">
      <div *ngIf="sidebarOpen" class="text-sm text-gray-400 mb-2">{{ username }}</div>
      <button
        (click)="logout()"
        class="flex items-center w-full px-2 py-2 text-sm hover:bg-gray-700 rounded transition-colors"
      >
        <span class="text-xl w-8 text-center">&#128682;</span>
        <span *ngIf="sidebarOpen" class="ml-3">Cerrar sesion</span>
      </button>
    </div>
  </aside>

  <!-- Main content -->
  <div class="flex-1 flex flex-col overflow-hidden">
    <!-- Header -->
    <header class="bg-white shadow-sm border-b border-gray-200 px-6 py-4">
      <div class="flex items-center justify-between">
        <h2 class="text-xl font-semibold text-gray-800">{{ getPageTitle() }}</h2>
        <div class="flex items-center gap-4">
          <span class="text-sm text-gray-500">{{ userRoles.join(', ') }}</span>
          <div class="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center text-white text-sm font-medium">
            {{ username | slice: 0:1 | uppercase }}
          </div>
        </div>
      </div>
    </header>

    <!-- Page content -->
    <main class="flex-1 overflow-y-auto p-6">
      <router-outlet></router-outlet>
    </main>
  </div>
</div>
